const parseMessage = (input: string): SSEMessage => {
  const message: { data: Array<string>; event?: string; id?: string; retry?: number } = { data: [] }
  for (const line of input.split("\n")) {
    const index = line.indexOf(":")
    const field = index === -1 ? line : line.slice(0, index)
    const value = index === -1 ? "" : line.slice(index + 1).replace(/^ /, "")
    if (field === "data") message.data.push(value)
    else if (field === "event") message.event = value
    else if (field === "id") message.id = value
    else if (field === "retry") message.retry = Number(value)
  }
  return { ...message, data: message.data.join("\n") }
}

